import React, { useState } from 'react';
import axios from 'axios';

function Settings({ user, onClose, onUpdate, applyTheme }) {
  const [activeTab, setActiveTab] = useState('profile');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  
  const [profile, setProfile] = useState({
    displayName: user.displayName || '',
    username: user.username || '',
    email: user.email || '',
    phone: user.phone || '',
    bio: user.bio || ''
  });

  const [settings, setSettings] = useState({
    theme: user.theme || 'dark',
    notifications: user.notifications === 1,
    soundEnabled: user.soundEnabled === 1
  });

  const [avatarFile, setAvatarFile] = useState(null);
  const [avatarPreview, setAvatarPreview] = useState(user.avatar ? `http://localhost:5000${user.avatar}` : null);

  const handleAvatarChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const uploadAvatar = async () => {
    if (!avatarFile) return null;
    
    const formData = new FormData();
    formData.append('avatar', avatarFile);
    
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        throw new Error('Токен не найден');
      }
      
      const res = await axios.post('http://localhost:5000/api/upload-avatar', formData, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'multipart/form-data'
        }
      });
      return res.data.avatar;
    } catch (err) {
      console.error('Ошибка загрузки аватарки:', err);
      throw err;
    }
  };

  const handleSaveProfile = async () => {
    setLoading(true);
    setError('');
    setSuccess('');
    
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        throw new Error('Токен не найден');
      }
      
      let avatarUrl = user.avatar;
      if (avatarFile) {
        avatarUrl = await uploadAvatar();
      }
      
      const res = await axios.put('http://localhost:5000/api/profile', profile, {
        headers: { 
          'Authorization': `Bearer ${token}` 
        }
      });
      
      const updatedUser = { ...res.data, avatar: avatarUrl };
      localStorage.setItem('user', JSON.stringify(updatedUser));
      onUpdate(updatedUser);
      setSuccess('Профиль обновлён! ✨');
    } catch (err) {
      console.error('Ошибка:', err);
      setError(err.response?.data?.error || err.message || 'Ошибка обновления');
    } finally {
      setLoading(false);
    }
  };

  const handleSaveSettings = async () => {
    setLoading(true);
    setError('');
    setSuccess('');
    
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        throw new Error('Токен не найден');
      }
      
      const res = await axios.put('http://localhost:5000/api/settings', settings, {
        headers: { 
          'Authorization': `Bearer ${token}` 
        }
      });
      
      const updatedUser = { ...user, ...res.data };
      localStorage.setItem('user', JSON.stringify(updatedUser));
      onUpdate(updatedUser);
      
      // Применяем тему сразу
      if (applyTheme) {
        applyTheme(settings.theme);
      }
      
      setSuccess('Настройки сохранены! ⚙️');
    } catch (err) {
      console.error('Ошибка:', err);
      setError(err.response?.data?.error || err.message || 'Ошибка сохранения');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="settings-modal">
      <div className="settings-content">
        <div className="settings-header">
          <h2>Настройки</h2>
          <button onClick={onClose} className="close-button">✕</button>
        </div>

        <div className="settings-tabs">
          <button
            onClick={() => setActiveTab('profile')}
            className={`settings-tab ${activeTab === 'profile' ? 'active' : ''}`}
          >
            👤 Профиль
          </button>
          <button
            onClick={() => setActiveTab('settings')}
            className={`settings-tab ${activeTab === 'settings' ? 'active' : ''}`}
          >
            ⚙️ Настройки мессенджера
          </button>
        </div>

        <div className="settings-body">
          {error && (
            <div className="error-message">
              ❌ {error}
            </div>
          )}

          {success && (
            <div className="success-message">
              ✓ {success}
            </div>
          )}

          {activeTab === 'profile' && (
            <div>
              {/* Аватарка */}
              <div className="avatar-section">
                <div 
                  className="avatar-upload" 
                  onClick={() => document.getElementById('avatar-input').click()}
                >
                  {avatarPreview ? (
                    <img src={avatarPreview} alt="avatar" />
                  ) : (
                    <div className="avatar-placeholder">
                      {user.displayName[0].toUpperCase()}
                    </div>
                  )}
                  <input
                    id="avatar-input"
                    type="file"
                    accept="image/*"
                    onChange={handleAvatarChange}
                    style={{ display: 'none' }}
                  />
                </div>
                <p>Нажмите на аватарку, чтобы изменить</p>
              </div>

              {/* Поля профиля */}
              <div className="form-group">
                <label>Имя</label>
                <input
                  type="text"
                  value={profile.displayName}
                  onChange={(e) => setProfile({...profile, displayName: e.target.value})}
                />
              </div>

              <div className="form-group">
                <label>Username</label>
                <input
                  type="text"
                  value={profile.username}
                  onChange={(e) => setProfile({...profile, username: e.target.value})}
                />
                <small>Только латиница и цифры</small>
              </div>

              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  value={profile.email}
                  onChange={(e) => setProfile({...profile, email: e.target.value})}
                />
              </div>

              <div className="form-group">
                <label>Телефон</label>
                <input
                  type="tel"
                  value={profile.phone || ''}
                  onChange={(e) => setProfile({...profile, phone: e.target.value})}
                />
                <small>Необязательно</small>
              </div>

              <div className="form-group">
                <label>О себе</label>
                <textarea
                  value={profile.bio || ''}
                  onChange={(e) => setProfile({...profile, bio: e.target.value})}
                  rows="4"
                  placeholder="Расскажите немного о себе..."
                />
              </div>
            </div>
          )}

          {activeTab === 'settings' && (
            <div>
              <div className="settings-section">
                <h3>Внешний вид</h3>
                
                <div className="form-group">
                  <label>Тема оформления</label>
                  <select
                    value={settings.theme}
                    onChange={(e) => setSettings({...settings, theme: e.target.value})}
                  >
                    <option value="dark">🌙 Тёмная</option>
                    <option value="light">☀️ Светлая</option>
                    <option value="purple">💜 Фиолетовая</option>
                  </select>
                </div>
              </div>

              <div className="settings-section">
                <h3>Уведомления</h3>
                
                <label className="checkbox-label">
                  <input
                    type="checkbox"
                    checked={settings.notifications}
                    onChange={(e) => setSettings({...settings, notifications: e.target.checked})}
                  />
                  <span>Включить уведомления</span>
                </label>

                <label className="checkbox-label">
                  <input
                    type="checkbox"
                    checked={settings.soundEnabled}
                    onChange={(e) => setSettings({...settings, soundEnabled: e.target.checked})}
                  />
                  <span>Звук сообщений</span>
                </label>
              </div>

              <div className="settings-section">
                <h3>Конфиденциальность</h3>
                
                <label className="checkbox-label">
                  <input
                    type="checkbox"
                    checked={true}
                    onChange={() => {}}
                  />
                  <span>Показывать статус "онлайн"</span>
                </label>

                <label className="checkbox-label">
                  <input
                    type="checkbox"
                    checked={true}
                    onChange={() => {}}
                  />
                  <span>Показывать время последнего визита</span>
                </label>
              </div>

              <div className="settings-section">
                <h3>Данные</h3>
                
                <button 
                  className="danger-button"
                  onClick={() => {
                    if (window.confirm('Вы уверены? Это действие нельзя отменить.')) {
                      alert('Функция в разработке');
                    }
                  }}
                >
                  🗑️ Удалить аккаунт
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="settings-footer">
          <button onClick={onClose} className="cancel-button">
            Отмена
          </button>
          <button
            onClick={activeTab === 'profile' ? handleSaveProfile : handleSaveSettings}
            disabled={loading}
            className="save-button"
          >
            {loading ? 'Сохранение...' : 'Сохранить'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default Settings;
